const Q_CHEMISTRY_2018_MODEL_III=[{"id": "objective>Chemistry>2018-Model-III>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">1.0g of limestone was treated with excess 0.5 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>. The acid left at the end of reaction required 30cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 0.025moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> NaOH for complete neutralization. What is the original volume of acid?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">57cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">21cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">33cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">68cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CaCO_(3(g) + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> → CaSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> <br/> From equation of reaction <br/> 1 mole of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> requires 1 mole of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />100</td><td style=\"text-align:center;\">mole</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">required</td><td style=\"text-align:center;\">1<hr size=\"1\" />100</td><td style=\"text-align:center;\">mole</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></td></tr></table></div> <br/> 0.01mole of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> acid reacted completely with CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>. <br/> Since H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> was in excess <br/> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 2NaOH → Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">No</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">moles</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">NaOH</td><td style=\"text-align:center;\">that</td><td style=\"text-align:center;\">reacted</td><td style=\"text-align:center;\">with</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">acid</td><td style=\"text-align:center;\">left</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">30<hr size=\"1\" />1000</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">0.025</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">7.5</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>mol</td><td style=\"text-align:center;\">from</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">equation</td></tr></table></div> <br/> 1 mole of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> needed 2 mole of NaOH for neutralization <br/> x mole of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> needs 7.5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>mol <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">therefore</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">7.5×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span><hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3.75</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span></td></tr></table></div> <br/> the n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></span> = 3.75 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> <br/> The total no of moles of acid  = 0.01 + 3.75 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> = 0.010375 <br/> since number of moles = concentration × volume <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Volume</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">no of moles<hr size=\"1\" />concentration</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.010375<hr size=\"1\" />0.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.02075</td></tr></table></div> <br/> the original volume of acid use = 0.02075 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> or 0.02075 × 1000 <br/> 20.75cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  = 21cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2018-Model-III>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The atom with the electron configuration  <br/> 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3d<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span>4s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>4p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> is in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">period 4, p- block</div>", "<div style=\"font-family:Cambria;font-size:17px;\">period 3, p- block</div>", "<div style=\"font-family:Cambria;font-size:17px;\">period 4, d- block</div>", "<div style=\"font-family:Cambria;font-size:17px;\">period 3, d- block</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electron configuration 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3d<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span>4s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>4p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> corresponds to a Selenium (Se) atom. Selenium is in the 4th period and in the p-block of the periodic table. The p-block elements are those in which the last electron enters the outermost p-orbital.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2018-Model-III>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the oxidation number of Nitrogen in HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">+3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+5</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation number of Nitrogen in HNO3 (Nitric acid) is +5. This is because the oxidation number of Hydrogen is +1 and that of Oxygen is -2. Since the compound is neutral, the sum of the oxidation numbers is zero. Therefore, the oxidation number of Nitrogen is calculated as follows: +1 + N + 3(-2) = 0. Solving for N gives N = +5.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2018-Model-III>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about atoms of a metal is correct? They</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">readily accept electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are soft</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are held together by covalent bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are held together by a sea of electron cloud</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Metals are effectively lots of positively charged ions with a cloud/sea of delocalised electrons. This means the electrons are free to move throughout the metal, and is also why metals can conduct electricity as the electrons can move. The more delocalised electrons a metal has, the stronger it will be held together.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2018-Model-III>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The best indicator to use for the titration of ethanoic acid with sodium hydroxide is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">methyl red.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">methyl orange.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phenolphthalein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">screened methyl orange</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Phenolphthalein is an indicator that is commonly used in acid-base titrations. It is colorless in acidic solutions (pH below 8.2) and turns pink or magenta in alkaline solutions (pH above 10). In the titration of ethanoic acid (acetic acid) with sodium hydroxide (a strong base), the pH will change from acidic to alkaline as the acid is neutralized by the base.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2018-Model-III>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following laws is general gas equation derived?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Boyle's law and charles' law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gay-lussac's law and Graham's law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Henry's Law and Graham's Law </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dalton's law and Gay-lussac's law</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The general gas equation, PV = nRT, is derived from Boyle's law (at constant temperature, the volume of a given mass of a gas is inversely proportional to its pressure) and Charles' law (at constant pressure, the volume of a given mass of a gas is directly proportional to its absolute temperature).</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2018-Model-III>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following properties indicate that an element is a metal. It <br/>  I.  reacts with oxygen to form an acidic oxide <br/> II. forms ionic chlorides <br/> III. has variable oxidation states <br/> IV. displaces hydrogen from dilute HCl</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">-ionization behaviour <br/> The atoms of non-metals usually have four to seven valence electrons. They have a great tendency to ionize by accepting electrons to form negative ions. <br/> - Reaction with acids <br/> A metal which is more electro positive than hydrogen readily displaces the hydrogen ion, H+, from an acid.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2018-Model-III>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In view of relationship between conductivity of an electrolytes and its concentration. If the concentraion reduces, what happens to the conductivity of the electrolytes?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decreases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is Unaffected </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduces to zero</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> When the concentration of the electrolyte is reduced, the conductivity will decrease too. This is because they are directly proportional. The number of ions per unit volume that carries current in the solution also decreases after dilution. This occurs vice versa when the concentration of the electrolyte is increased. <br/>  <br/> </div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>2018-Model-III>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What current in amperes will deposit 12.8g of Copper in 2 hours 30 minutes? <br/> [Cu = 64, F = 96500 Coulomb mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.3</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Number</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">moles</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">Cu</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12.8<hr size=\"1\" />64</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.2</td><td style=\"text-align:center;\">mol</td></tr></table></div> <br/> Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Cu <br/> 1 mole of Cu → 2F of electricity <br/> 0.2 mole of Cu → x <br/> x = 0.4 F <br/> But F = 96,500 coloumb of electricity  <br/> x = 0.4 x 96,500 = 38600 <br/> Recall Q = It <br/> 38,600 = I × 2.5 × 60 × 60 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">38,600<hr size=\"1\" />25×3600</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">38,600<hr size=\"1\" />9000</td></tr></table></div> <br/> I = 4.289 ≈ 4.3 Amperes</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2018-Model-III>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following bond types is intermolecular?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Covalent bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ionic bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Metallic bond</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen bond is an intermolecular force which arises when hydrogen is covalently linked to elements like nitrogen, oxygen and fluorine.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2018-Model-III>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the following reaction equation:  <br/>  SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">aq</span> + ye<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span>  <br/>  The value of y in the equation is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">-2 + 2 + y(-1) = -2 <br/> 0 - y = -2 <br/> y = +2 <br/>  The value of y in the equation is +2</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2018-Model-III>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the following reaction equation <br/> N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ⇌ 2NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>; ∆H = -92kJ <br/>  <br/> Increasing the temperature of the reaction would <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shift the equilibrium to the right</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the yield of ammonia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease the amount of hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease the yield of ammonia</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In this case, an increase in in temperature will cause the equilibrium position to shift to the left thereby decreasing the yield of ammonia.</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2018-Model-III>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A particle that contains 20 proton, 20 neutrons and 18 electron could be written as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">40</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">20</span>Ca</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">38</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">20</span>Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">40</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">20</span>Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">40</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">20</span>Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The atomic number (number of protons) of the particle is 20, which corresponds to Calcium (Ca). The mass number (number of protons + neutrons) is 40. The particle has 2 fewer electrons than protons, which means it has a charge of +2. Therefore, the particle is a Calcium ion with a charge of +2, represented as <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">40</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">20</span>Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2018-Model-III>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electron configuration of carbon atom in its excited state is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2px<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2py<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2px<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span>2py<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span>2px<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span>2py<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span>2pz<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2px<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span>2py<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span>2pz<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">-So any electron configuration in which the last electron (again, the valence electron) is in a higher energy orbital, this element is said to be in an excited state.  <br/> -When a carbon atom becomes excited by absorbing energy, one of its 2s electrons is promoted into the 2p sublevel. </div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>2018-Model-III>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Electropositivity of elements across the periodic table normally</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">remains constant down the group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases across the period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreases across the period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreases down the group</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electropositivity is known to increase down groups and decrease across periods in the modern periodic table (i.e., electropositivity decreases from left to right and it increases from up to down).</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALI METALS"}, {"id": "objective>Chemistry>2018-Model-III>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During flame test, what colour is observed when Sodium ion is introduced to a non-luminous flame?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Crimson</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Golden-yellow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lilac</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reddish-brown</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During a flame test, Sodium ions give a characteristic golden-yellow color. This is due to the excitation of electrons in the sodium ion, which when return to their ground state, emit light of specific wavelength (yellow in case of Sodium).</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2018-Model-III>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Electropositivity of elements across the periodic table normally</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">remains constant down the group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases across the period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreases across the period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreases down the group</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electropositivity is known to increase down groups and decrease across periods in the modern periodic table (i.e., electropositivity decreases from left to right and it increases from up to down).</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2018-Model-III>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC name of the compound CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH(CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)CHCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2 - methyl but - 1 - ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 - methyl but - 2 - ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 - methyl but - 1 - ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 - methyl but - 2 - ene</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The longest carbon chain in the compound is four carbons long, which makes it a butene. The double bond is on the second carbon, hence the '2 - ene'. The methyl group (CH3) is also on the second carbon, hence the '2 - methyl'.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2018-Model-III>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 0.125 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> Sodium hydroxide solution required 15.0cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a solution of tetraoxosulphate (VI) acid for complete neutralization. What is the mass concentration of the acid solution? <br/> (Na = 23, O = 16, S = 32, H = 1)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15.6 gdm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.2 gdm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.65 gdm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.82gdm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equation of the reaction  <br/> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 2NaOH → Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> = ? C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = 0.125 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> = 5.cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = 25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span><hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>×15<hr size=\"1\" />0.125×25</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.125 × 25<hr size=\"1\" />15 × 2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3.125<hr size=\"1\" />30</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.104moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td></tr></table></div> <br/> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> = (1 x 2) + 32 + (16 x 4) = 98gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Concentration of the acid (gdm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>) = Conc. (moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> x molar mass) <br/>  = (0.104 × 98) <br/> Mass conc. = 10.2gdm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2018-Model-III>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following acids would form normal salt only?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tetraoxosulphate(VI) acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trioxonitrate(V) acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tetraoxophosphate(V) acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trioxosulphate(IV) acid</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trioxonitrate(V) acid, also known as nitric acid (HNO3), forms only normal salts. A normal salt is a salt that is formed by complete replacement of the hydrogen ion in an acid by a metal or ammonium ion. Nitric acid is a monobasic acid, meaning it has only one replaceable hydrogen ion. Therefore, it can only form normal salts.</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>2018-Model-III>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Waste plastic accumulate in the soil and pollute the environment because plastic materials are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Insoluble in water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Non-biodegradable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Easily effected by heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Inflammable </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plastics are non-biodegradable wastes, i.e they cannot be decomposed by micro-organnisms or biological activities. <br/> </div>", "topic": "ENVIRONMENTAL POLLUTION : SOIL POLLUTION"}, {"id": "objective>Chemistry>2018-Model-III>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An element that forms a Covalent chloride is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sodium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Potassium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magnesium</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen forms a covalent chloride (HCl). In a covalent bond, the bonding electrons are shared by the bonded atoms. This is different from ionic bonding, where one atom completely transfers one or more electrons to another atom. Sodium, Potassium, and Magnesium are metals and they form ionic chlorides, not covalent chlorides.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2018-Model-III>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the differece between the electronegativities of two elements is large, the type of bond that can be formed between them is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">covalent bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metallic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the difference in electronegativity between two atoms is large, the bond formed is typically ionic. This is because one atom will attract the shared electrons much more strongly than the other, resulting in an electron transfer and the formation of ions. These ions then attract each other to form an ionic bond.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2018-Model-III>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following electronic configurations represents that of  noble gas?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2, 8, 8, 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 8, 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 6</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Noble gases are elements with full electron shells. For the first six periods of the periodic table, this means they have configurations ending in '2, 8'. The only option that fits this description is '2, 8', which represents the noble gas Neon.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2018-Model-III>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When air in a syringe is compressed such that there is no change in temperature, the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">air liquefies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intermolecular space increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">density decreases</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since the temperature of air remain constant.So, it is a isothermal process. <br/>   PV=K <br/> This eq. shows that on increasing pressure, the volume gets reduced and vice-versa. <br/> Since the syringe is slowly compressed, volume is decreasing. <br/> Therefore, the pressure inside the syringe will increases because the molecules now hit the syringe walls more frequently.</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2018-Model-III>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An oxide has the following properties. It <br/> I. is a white powder <br/> II. reacts with HCl. <br/> III. reacts with NaOH <br/> IV. is insoluble in water <br/> The oxide is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkaline</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amphoteric</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acidic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutral</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An amphoteric oxide is an oxide that can act as either an acid or base in a reaction to produce a salt and water.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2018-Model-III>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the reaction represented by the equation: <br/> 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ⇋ 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> , ΔH = -197 kjmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> which of the following conditions will not increase the yield of sulphur (VI) oxide?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increase in temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decrease in temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in pressure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Addition of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> into the mixture</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction given is exothermic (ΔH is negative), meaning it releases heat. According to Le Chatelier's principle, increasing the temperature will shift the equilibrium to the left, favoring the reactants and decreasing the yield of sulfur (VI) oxide.</div>", "topic": "CHEMICAL EQUILIBRA : LE CHATELIER'S PRINCIPLE AND EQUILIBRIUM CONSTANT"}, {"id": "objective>Chemistry>2018-Model-III>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">All of these statements in the option given is false of Le Chateliers' principle for an Endothermic reaction except?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Addition of a positive catalyst will cause an increase in the value of the equilibrium constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Addition of a positive catalyst will cause decrease in the value of the equilibrium constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decrease in temperature will cause an increase in the value of the equilibrium constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decrease in temperature will cause a decrease in the value of the equilibrium constant</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Le Chatelier's principle states that if a dynamic equilibrium is disturbed by changing the conditions, the position of equilibrium shifts to counteract the change. For an endothermic reaction, decreasing the temperature will shift the equilibrium to the left, decreasing the value of the equilibrium constant. This is because the reaction will try to counteract the decrease in temperature by absorbing more heat, which is the reverse reaction.</div>", "topic": "CHEMICAL EQUILIBRA : LE CHATELIER'S PRINCIPLE AND EQUILIBRIUM CONSTANT"}, {"id": "objective>Chemistry>2018-Model-III>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The compound that would have  flame test colouration of lilac and give a white precipitate with aqueous barium chloride followed by dilute hydrochloric acid is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NaCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CuCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">KCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lilac flame colouration indicates the presence of K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> that a white precipitate is insoluble in dilute HCl is formed indicates the presence of SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span>. Hence, the compound is K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2018-Model-III>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the following reaction equation: <br/> CaO    +    SiO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> →  CaSiO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/> Silicon(IV) oxide is acting as <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a basic oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a reducing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an acidic oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an oxidizing agent</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Silicon dioxide is an acidic oxide. It will react with strong bases to form silicate salts, SiO2 is acidic oxide because Si is non-metal. Oxides of non-metals are acidic in nature.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2018-Model-III>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction between 5g of iron filings and 0.5moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> HCl can be made to proceed faster by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">using 0.25moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> acid instead</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adding 0.5moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> NaOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cooling the reaction vessel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adding some concentrated acid</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of a chemical reaction is directly proportional to the concentration. Addition of some concentration increases the rate of chemical reaction.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2018-Model-III>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compound is used as a fire extinguisher?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Carbon (ii) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur IV oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon (iv) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ammonia</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon(IV)oxide does not support ordinary combustion and it is also denser than air hence it is used in fire extinguisher.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : CARBON"}, {"id": "objective>Chemistry>2018-Model-III>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a physical property?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">flammability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solubility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">melting point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">viscosity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Flammability is the measurability or propensity for a compound to combust (i.e chemically react with oxygen,) this is a chemical property.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : CHEMICAL AND PHYSICAL CHANGES"}, {"id": "objective>Chemistry>2018-Model-III>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following laws or theory cannot be explained by the application of the kinetic theory of gases?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Dalton's atomic theory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Charles' law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gay-lussac's law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Boyle's law</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dalton's atomic theory cannot be explained by the application of the kinetic theory of gases because it deals with the atomic-level structure and behavior of matter, which is beyond the scope of the kinetic theory's focus on the macroscopic behavior of gas particles. The other laws (Charles' law, Gay-Lussac's law, and Boyle's law) can be well understood and explained by the kinetic theory of gases, as they relate to the macroscopic properties and behaviors of gases and their constituent particles.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2018-Model-III>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following substances is an ore of Iron?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bauxite </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cassiterite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Haematite </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Steel</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Haematite is an ore of Iron. An ore is a naturally occurring solid material from which a metal or valuable mineral can be extracted profitably. Bauxite is an ore of Aluminium, Cassiterite is an ore of Tin, and Steel is not an ore but an alloy of Iron.</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2018-Model-III>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following method are suitable method of preparing simple salts except?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hydrogenation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neutralization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Double decomposition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reaction of an acid with a metal</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogenation means to treat with hydrogen. It is is a chemical reaction between molecular hydrogen (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) and another compound or element, usually in the presence of a catalyst such as nickel, palladium or platinum. Hydrogenation reduces double and triple bonds in hydrocarbons.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2018-Model-III>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">ΔS is positive in the process</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 2HI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 2NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Boiling of water CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> is the only change among the options that leads to increased randomness or positive entropy change</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>2018-Model-III>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is emitted during the disintegration of Ba nucleus as shown by the equation below? <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">138</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">56</span>Ba → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">134</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">54</span>X</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Alpha particles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Beta particles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gamma rays </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neutrons </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alpha particles <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">138</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">56</span>Ba → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">134</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">54</span>X + Y <br/> The Superscript of Y has to be 138 - 134 = 4 and the subscript has to be 56 - 54 = 2 <br/> Thus, we have γ, which is <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>He</div>", "topic": "NUCLEAR CHEMISTRY : RADIOACTIVITY"}, {"id": "objective>Chemistry>2018-Model-III>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gases is alkaline?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, also known as ammonia, is a weak base and therefore is alkaline. When dissolved in water, it reacts with water to form ammonium ions and hydroxide ions, increasing the pH of the solution.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2018-Model-III>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What volume of 0.25moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> solution would give 13.25g Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> on evaporation to dryness? [Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 106gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">250cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">500cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">750cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,250cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Number of mole of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> in solution = Number of mole of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> in the residue  <br/> Number of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> in solution = Conc. (moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> × vol <br/>  = 0.25 × V = 0.25V <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Number</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">moles</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">residue</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">13.25g<hr size=\"1\" />106gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td></tr></table></div> <br/> 0.25V = 0.125 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.125<hr size=\"1\" />0.25</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.50dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td></tr></table></div> <br/> V = (0.50 × 1000)cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 500cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}];
